        }
        canvas {
            display: block;
        }
        #controls {
            margin-top: 20px;
        }
        button {
            padding: 10px 25px;
            font-size: 1rem;
            cursor: pointer;
            background: #ff4757;
            color: white;
            border: none;
            border-radius: 4px;
            transition: background 0.2s, transform 0.1s;
            font-weight: bold;
        }
        button:hover {
            background: #ff6b81;
        }
        button:active {
            transform: scale(0.95);
        }
    </fmt>
    <style>
        /* Redefining for cleaner look */
        #reset { background: #e74c3c; }
        #reset:hover { background: #ff6b81; }
    </style>
</head>
<body>

    <div id="hud">
        <div class="stat">Completed: <span id="completed">0</span>/24</div>
        <div class="stat">Time: <span id="timer">0</span>s</div>
    </div>

    <div id="maze-container">
        <canvas id="maze" width="400" height="400"></canvas>
    </div>

    <div id="controls">
        <button id="reset">Reset Game</button>
    </div>

    <script>
        class MazeGame {
            constructor() {
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');
                this.cols = 20;
                this.rows = 20;
                this.cellSize = 400 / this.cols;
                this.bots = [];
                this.completedCount = 0;
                this.ticks = 0;
                this.elapsedMs = 0;
                this.cells = [];
                this.exitCell = { x: this.cols - 1, y: this.rows - 1 };
                this.spawnCell = { x: 0, y: 0 };

                // Expose API to window as required
                window.game = {
                    get bots() { return this.bots; },
                    get completed() { return this.completedCount; },
                    get elapsedMs() { return this.elapsedMs; },
                    tick: (n) => this.tick(n),
                    reset: () => this.reset()
                };

                document.getElementById('reset').addEventListener('click', () => this.reset());

                this.reset();
                this.startAnimation();
            }

            reset() {
                this.ticks = 0;
                this.elapsedMs = 0;
                this.completedCount = 0;
                this.generateMaze();
                this.initBots();
                this.updateDOM();
            }

            generateMaze() {
                // Initialize cells
                this.cells = [];
                for (let y = 0; y < this.rows; y++) {
                    for (let x = 0; x < this.cols; x++) {
                        this.cells.push({
                            x, y,
                            walls: [true, true, true, true], // top, right, bottom, left
                            visited: false
                        });
                    }
                }

                // DFS to create perfect maze
                const stack = [];
                let current = this.cells[0];
                current.visited = true;
                stack.push(current);

                while (stack.length > 0) {
                    let next = this.getUnvisitedNeighbor(current);
                    if (next) {
                        next.visited = true;
                        this.removeWallBetween(current, next);
                        stack.push(next);
                        current = next;
                    } else {
                        current = stack.pop();
                        if (stack.length > 0) current = stack[stack.length - 1];
                    }
                }
                this.cells.forEach(c => c.visited = false); // Reset visited for future use
            }

            getUnvisitedNeighbor(cell) {
                const neighbors = this.getNeighbors(cell).filter(n => !n.visited);
                return neighbors.length > 0 ? neighbors[Math.floor(Math.random() * neighbors.length)] : null;
            }

            getNeighbors(cell) {
                const neighbors = [];
                const { x, y } = cell;
                const directions = [[0, -1], [1, 0], [0, 1], [-1, 0]]; // top, right, bottom, left
                for (let [dx, dy] of directions) {
                    const nx = x + dx, ny = y + dy;
                    if (nx >= 0 && nx < this.cols && ny >= 0 && ny < this.rows) {
                        neighbors.push(this.cells[ny * this.cols + nx]);
                    }
                }
                return neighbors;
            }

            removeWallBetween(a, b) {
                const dx = a.x - b.x;
                const dy = a.y - b.y;
                if (dx === 1) { a.walls[3] = false; b.walls[1] = false; } // a left of b
                else if (dx === -1) { a.walls[1] = false; b.walls[3] = false; } // a right of b
                else if (dy === 1) { a.walls[0] = false; b.walls[2] = false; } // a above b
                else if (dy === -1) { a.walls[2] = false; b.walls[0] = false; } // a below b
            }

            initBots() {
                this.bots = [];
                const path = this.findPath(this.spawnCell, this.exitCell);
                for (let i = 0; i < 24; i++) {
                    this.bots.push({
                        x: this.spawnCell.x,
                        y: this.spawnCell.y,
                        path: path,
                        delay: Math.floor(Math.random() * 150), // Staggered start
                        currentStep: 0,
                        finished: false,
                        color: `hsl(${(i * 360 / 24)}, 80%, 60%)`
                    });
                }
            }

            findPath(start, end) {
                // BFS to find shortest path in the maze
                const queue = [[{ x: start.x, y: start.y }]];
                const visited = new Set([`${start.x},${start.y}`]);

                while (queue.length > 0) {
                    const path = queue.shift();
                    const curr = path[path.length - 1];

                    if (curr.x === end.x && curr.y === end.y) return path;

                    const cell = this.cells[curr.y * this.cols + curr.x];
                    const directions = [[0, -1, 0], [1, 0, 1], [0, 1, 2], [-1, 0, 3]]; // dx, dy, wallIndex

                    for (let [dx, dy, wallIdx] of directions) {
                        if (!cell.walls[wallIdx]) {
                            const nx = curr.x + dx, ny = curr.y + dy;
                            const key = `${nx},${ny}`;
                            if (nx >= 0 && nx < this.cols && ny >= 0 && ny < this.rows && !visited.has(key)) {
                                visited.add(key);
                                queue.push([...path, { x: nx, y: ny }]);
                            }
                        }
                    }
                }
                return [];
            }

            tick(n) {
                for (let i = 0; i < n; i++) {
                    this.internalTick();
                }
                // Update DOM immediately for automated tests
                this.updateDOM();
            }

            internalTick() {
                this.ticks++;
                this.elapsedMs = this.ticks * 16.67; // Simulate ~60fps ticks
                this.bots.forEach(bot => {
                    if (!bot.finished && this.ticks > bot.delay) {
                        bot.currentStep++;
                        const nextPos = bot.path[bot.currentStep];
                        if (nextPos) {
                            bot.x = nextPos.x;
                            bot.y = nextPos.y;
                            if (bot.x === this.exitCell.x && bot.y === this.exitCell.y) {
                                bot.finished = true;
                                this.completedCount++;
                            }
                        }
                    }
                });
            }

            updateDOM() {
                document.getElementById('completed').textContent = this.completedCount;
                document.getElementById('timer').textContent = (this.elapsedMs / 1000).toFixed(1);
            }

            startAnimation() {
                const loop = () => {
                    this.internalTick(); // Continuous simulation for visual play
                    this.draw();
                    requestAnimationFrame(loop);
                };
                requestAnimationFrame(loop);
            }

            draw() {
                const ctx = this.ctx;
                const sz = this.cellSize;
                ctx.clearRect(0, 0, 400, 400);

                // Draw Background/Path
                ctx.fillStyle = '#111';
                ctx.fillRect(0, 0, 400, 400);

                // Draw Walls
                ctx.strokeStyle = '#555';
                ctx.lineWidth = 2;
                this.cells.forEach(cell => {
                    const cx = cell.x * sz;
                    const cy = cell.y * sz;
                    ctx.beginPath();
                    if (cell.walls[0]) { ctx.moveTo(cx, cy); ctx.lineTo(cx + sz, cy); } // top
                    if (cell.walls[1]) { ctx.moveTo(cx + sz, cy); ctx.lineTo(cx + sz, cy + sz); } // right
                    if (cell.walls[2]) { ctx.moveTo(cx, cy + sz); ctx.lineTo(cx + sz, cy + sz); } // bottom
                    if (cell.walls[3]) { ctx.moveTo(cx, cy); ctx.lineTo(cx, cy + sz); } // left
                    ctx.stroke();
                });

                // Draw Exit and Spawn
                ctx.fillStyle = 'rgba(0, 255, 100, 0.3)';
                ctx.fillRect(this.exitCell.x * sz, this.exitCell.y * sz, sz, sz);
                ctx.fillStyle = 'rgba(0, 150, 255, 0.3)';
                ctx.fillRect(this.spawnCell.x * sz, this.spawnCell.y * sz, sz, sz);

                // Draw Bots
                this.bots.forEach(bot => {
                    const bx = bot.x * sz + sz / 2;
                    const by = bot.y * sz + sz / 2;
                    ctx.beginPath();
                    ctx.arc(bx, by, sz / 3, 0, Math.PI * 2);
                    ctx.fillStyle = bot.color;
                    ctx.fill();
                    // Glow effect for active bots
                    if (!bot.finished) {
                        ctx.shadowBlur = 5;
                        ctx.shadowColor = bot.color;
                    } else {
                        ctx.shadowBlur = 0;
                    }
                });
                ctx.shadowBlur = 0; // Reset shadow for next draw
            }
        }

        // Initialize the game when script loads
        new MazeGame();
    </script>
</body>
</html>
